args.sparql:
SELECT ?supplier ?supplierLabel WHERE {
  wd:Q309095 p:P5995 ?statement.
  ?statement ps:P5995 ?supplier.
  ?statement pq:P580 ?start.
  OPTIONAL { ?statement pq:P582 ?end. }
  FILTER (?start <= "2012-01-01T00:00:00Z"^^xsd:dateTime && (!BOUND(?end) || ?end >= NOW()))
  SERVICE <http://wikiba.se/ontology#label> { bd:serviceParam wikibase:language "en". }
}

SELECT DISTINCT ?supplier ?supplierLabel WHERE {
  wd:Q309095 p:P5995 ?statement.
  ?statement ps:P5995 ?supplier.
  ?supplier rdfs:label ?supplierLabel.
  ?statement pq:P580 ?start.
  OPTIONAL { ?statement pq:P582 ?end. }
  FILTER(?start <= NOW() && (!BOUND(?end) || ?end >= "2012-01-01"^^xsd:date))
  FILTER(LANG(?supplierLabel) = "en")
}

SELECT ?supplier ?label WHERE {
  wd:Q309095 p:P176 ?statement.
  ?statement ps:P176 ?supplier.
  ?supplier rdfs:label ?label.
  OPTIONAL { ?statement pq:P580 ?start. }
  OPTIONAL { ?statement pq:P582 ?end. }
  FILTER (LANG(?label) = "en")
  FILTER ( (!BOUND(?start) || ?start <= "2023-01-01"^^xsd:date) &&
           (!BOUND(?end) || ?end >= "2012-01-01"^^xsd:date) )
}

SELECT DISTINCT ?supplier ?label WHERE {
  wd:Q309095 p:P5995 ?statement.
  ?statement ps:P5995 ?supplier.
  ?supplier rdfs:label ?label.
  ?statement pq:P580 ?start.
  OPTIONAL { ?statement pq:P582 ?end. }
  FILTER(LANG(?label) = "en")
  FILTER(
    YEAR(?start) <= YEAR(NOW()) &&
    (!BOUND(?end) || YEAR(?end) >= 2012)
  )
}
